-- 1. BẢNG COMPANIES (Thông tin doanh nghiệp)
CREATE TABLE COMPANIES (
    Ticker VARCHAR(10) PRIMARY KEY,
    CompanyName VARCHAR(255) NOT NULL,
    Industry VARCHAR(100) NOT NULL
);

-- 2. BẢNG DAILY_STOCK_PRICES (Dữ liệu giá thô lịch sử)
CREATE TABLE DAILY_STOCK_PRICES (
    PriceID SERIAL PRIMARY KEY, 
    Ticker VARCHAR(10) NOT NULL,
    TradingDate DATE NOT NULL,
    OpenPrice FLOAT NOT NULL, 
    HighPrice FLOAT NOT NULL,
    LowPrice FLOAT NOT NULL,
    ClosePrice FLOAT NOT NULL,
    Volume BIGINT NOT NULL,
    FOREIGN KEY (Ticker) REFERENCES COMPANIES(Ticker) ON DELETE CASCADE
);

-- 3. BẢNG TECHNICAL_INDICATORS (Các chỉ báo kỹ thuật nâng cao)
CREATE TABLE TECHNICAL_INDICATORS (
    IndicatorID SERIAL PRIMARY KEY, 
    PriceID INT UNIQUE NOT NULL,
    MA10 FLOAT,
    MA20 FLOAT,
    MA50 FLOAT,
    RSI FLOAT,
    MACD FLOAT,
    BollingerUpper FLOAT,
    BollingerLower FLOAT,
    TradingSignal VARCHAR(10) DEFAULT 'HOLD',
    FOREIGN KEY (PriceID) REFERENCES DAILY_STOCK_PRICES(PriceID) ON DELETE CASCADE
);

ON CONFLICT (Ticker) DO NOTHING; -- Tránh lỗi nếu mã công ty đã tồn tại từ trước

-- FILE SQL TU DONG SINH DE INSERT DU LIEU GIA VAO SUPABASE





WITH BaseData AS (
    SELECT 
        PriceID, Ticker, TradingDate, ClosePrice,
        LAG(ClosePrice) OVER (PARTITION BY Ticker ORDER BY TradingDate) AS PrevClose
    FROM DAILY_STOCK_PRICES
),

PriceChanges AS (
    SELECT *,
        CASE WHEN ClosePrice > PrevClose THEN ClosePrice - PrevClose ELSE 0 END AS Gain,
        CASE WHEN ClosePrice < PrevClose THEN PrevClose - ClosePrice ELSE 0 END AS Loss
    FROM BaseData
),

IndicatorsCalc AS (
    SELECT 
        PriceID, Ticker, TradingDate, ClosePrice,
        AVG(ClosePrice) OVER (PARTITION BY Ticker ORDER BY TradingDate ROWS BETWEEN 9 PRECEDING AND CURRENT ROW) AS MA10,
        AVG(ClosePrice) OVER (PARTITION BY Ticker ORDER BY TradingDate ROWS BETWEEN 19 PRECEDING AND CURRENT ROW) AS MA20,
        AVG(ClosePrice) OVER (PARTITION BY Ticker ORDER BY TradingDate ROWS BETWEEN 49 PRECEDING AND CURRENT ROW) AS MA50,
        
        AVG(Gain) OVER (PARTITION BY Ticker ORDER BY TradingDate ROWS BETWEEN 13 PRECEDING AND CURRENT ROW) AS AvgGain,
        AVG(Loss) OVER (PARTITION BY Ticker ORDER BY TradingDate ROWS BETWEEN 13 PRECEDING AND CURRENT ROW) AS AvgLoss,
        
        AVG(ClosePrice) OVER (PARTITION BY Ticker ORDER BY TradingDate ROWS BETWEEN 11 PRECEDING AND CURRENT ROW) - 
        AVG(ClosePrice) OVER (PARTITION BY Ticker ORDER BY TradingDate ROWS BETWEEN 25 PRECEDING AND CURRENT ROW) AS MACD,
        
        -- SỬA TẠI ĐÂY: Thay STDEV bằng stddev_samp chuẩn Postgres
        stddev_samp(ClosePrice) OVER (PARTITION BY Ticker ORDER BY TradingDate ROWS BETWEEN 19 PRECEDING AND CURRENT ROW) AS StdDev20
    FROM PriceChanges
),

FinalIndicators AS (
    SELECT 
        PriceID,
        ClosePrice,
        MA10,
        MA20,
        MA50,
        CASE 
            WHEN AvgLoss = 0 THEN 100 
            ELSE 100 - (100 / (1 + (AvgGain / AvgLoss))) 
        END AS RSI,
        MACD,
        -- SỬA TẠI ĐÂY: Thay ISNULL bằng COALESCE
        MA20 + (2 * COALESCE(StdDev20, 0)) AS BollingerUpper,
        MA20 - (2 * COALESCE(StdDev20, 0)) AS BollingerLower
    FROM IndicatorsCalc
)

-- Tiến hành Insert tự động vào bảng TECHNICAL_INDICATORS
SELECT 
    PriceID,
    ROUND(MA10::numeric, 2) AS MA10,
    ROUND(MA20::numeric, 2) AS MA20,
    ROUND(MA50::numeric, 2) AS MA50,
    -- SỬA TẠI ĐÂY: Thay ISNULL bằng COALESCE
    ROUND(COALESCE(RSI, 50)::numeric, 2) AS RSI,
    ROUND(COALESCE(MACD, 0)::numeric, 2) AS MACD,
    ROUND(BollingerUpper::numeric, 2) AS BollingerUpper,
    ROUND(BollingerLower::numeric, 2) AS BollingerLower,
    
    -- Logic phát tín hiệu Trading tự động khớp với xu hướng thực tế
    CASE 
        -- Mua khi giá chạm/vượt dải dưới Bollinger Bands HOẶC RSI rơi vào vùng quá bán (< 35)
        WHEN ClosePrice <= BollingerLower OR RSI <= 35 THEN 'BUY'
        -- Bán khi giá chạm/vượt dải trên Bollinger Bands HOẶC RSI rơi vào vùng quá mua (> 65)
        WHEN ClosePrice >= BollingerUpper OR RSI >= 65 THEN 'SELL'
        -- Các trường hợp còn lại tiếp tục nắm giữ theo dõi
        ELSE 'HOLD'
    END AS TradingSignal
FROM FinalIndicators;